DB.bySpellID = DB.bySpellID or nil

local function buildSpellIndex()
  local out = {}
  for mountID, data in pairs(DB.byMountID or {}) do
    local spellID = tonumber(data and data.spellID)
    if spellID and spellID > 0 then out[spellID] = mountID end
  end
  DB.bySpellID = out
end

function DB.GetByMountID(mountID)
  mountID = tonumber(mountID)
  return mountID and DB.byMountID and DB.byMountID[mountID] or nil
end

function DB.GetBySpellID(spellID)
  spellID = tonumber(spellID)
  if not spellID then return nil end
  if not DB.bySpellID then buildSpellIndex() end
  local mountID = DB.bySpellID and DB.bySpellID[spellID] or nil
  return mountID and DB.byMountID and DB.byMountID[mountID] or nil, mountID
end
